/*
 * Cloud Data Encryption Demo
 * Demonstrates basic XOR encryption for educational purposes
 * Note: Production systems should use established crypto libraries (OpenSSL, libsodium)
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#define MAX_DATA_SIZE 1024
#define KEY_SIZE 32

/* Structure to hold encrypted data with metadata */
typedef struct {
 unsigned char ciphertext[MAX_DATA_SIZE];
 unsigned char iv[16]; /* Initialization vector */
 size_t data_length;
 char timestamp[32];
} EncryptedData;

/* Simple XOR encryption - EDUCATIONAL ONLY */
/* In production, use AES-256-GCM or similar */
void encrypt_xor(const unsigned char *plaintext, 
 size_t len, 
 const unsigned char *key, 
 unsigned char *ciphertext) {
 for (size_t i = 0; i < len; i++) {
 /* XOR each byte with key byte (cycling through key) */
 ciphertext[i] = plaintext[i] ^ key[i % KEY_SIZE];
 }
}

/* Decrypt XOR encrypted data */
void decrypt_xor(const unsigned char *ciphertext, 
 size_t len, 
 const unsigned char *key, 
 unsigned char *plaintext) {
 /* XOR is symmetric - same operation decrypts */
 encrypt_xor(ciphertext, len, key, plaintext);
}

/* Simulate key derivation from password - simplified version */
void derive_key(const char *password, unsigned char *key) {
 size_t pass_len = strlen(password);
 for (int i = 0; i < KEY_SIZE; i++) {
 /* Simple key derivation (in production: use PBKDF2, bcrypt, or Argon2) */
 key[i] = (unsigned char)((password[i % pass_len] + i * 17) % 256);
 }
}

/* Simulate secure data storage for cloud */
int store_secure_data(const char *data, const char *password) {
 unsigned char key[KEY_SIZE];
 unsigned char encrypted[MAX_DATA_SIZE];

 size_t data_len = strlen(data);
 if (data_len > MAX_DATA_SIZE) {
 printf("Error: Data too large\n");
 return -1;
 }

 /* Derive encryption key from password */
 derive_key(password, key);

 /* Encrypt the data */
 encrypt_xor((const unsigned char *)data, data_len, key, encrypted);

 printf("Original data: %s\n", data);
 printf("Data encrypted successfully!\n");
 printf("Encrypted bytes (hex): ");
 for (size_t i = 0; i < data_len; i++) {
 printf("%02x", encrypted[i]);
 }
 printf("\n");

 /* Decrypt to verify */
 unsigned char decrypted[MAX_DATA_SIZE];
 decrypt_xor(encrypted, data_len, key, decrypted);
 decrypted[data_len] = '\0';

 printf("Decrypted data: %s\n", decrypted);

 return 0;
}

/* Cloud security best practices checklist */
void print_security_checklist() {
 printf("\n=== Cloud Data Protection Checklist ===\n");
 printf("[ ] Enable encryption at rest for all storage buckets\n");
 printf("[ ] Use strong encryption (AES-256 minimum)\n");
 printf("[ ] Implement proper key management (KMS)\n");
 printf("[ ] Enable encryption in transit (TLS 1.3)\n");
 printf("[ ] Implement access controls with least privilege\n");
 printf("[ ] Enable audit logging (CloudTrail, etc.)\n");
 printf("[ ] Regular key rotation (every 90 days recommended)\n");
 printf("[ ] Multi-factor authentication for admin access\n");
 printf("[ ] Data backup and disaster recovery plan\n");
 printf("[ ] Regular security audits and penetration testing\n");
 printf("========================================\n\n");
}

int main() {
 printf("Cloud Security: Data Encryption Demo\n");
 printf("=====================================\n\n");

 /* Example 1: Encrypt sensitive cloud data */
 const char *sensitive_data = "Customer SSN: 123-45-6789";
 const char *master_password = "SecureCloudPass2024!";

 printf("--- Storing sensitive customer data ---\n");
 store_secure_data(sensitive_data, master_password);

 /* Example 2: Multiple data fields */
 const char *medical_record = "Patient: John Doe, Diagnosis: Confidential";
 printf("\n--- Storing medical records (HIPAA compliance) ---\n");
 store_secure_data(medical_record, master_password);

 /* Print security best practices */
 print_security_checklist();

 return 0;
}
